udt:



















.confirm-modal {
    anchor: none;
    auto-size: grow;
}

.confirm-backdrop {
    anchor: none;
    auto-size: grow;
    background-color: 0xA0000000;
}

.confirm-dialog {
    size: 340 0;
    auto-size: fit;
    anchor: middle-center;
    flow: vertical;
    gap: 12;
    padding: 20;
}

.confirm-bg {
    anchor: none;
    auto-size: grow;
    background-color: 0xF0202020;
    border-radius: 10;
    stroke-color: 0x60FFD700;
    stroke-width: 1;
    stroke-inset: 1;
    stroke-radius: 8;
    shadow-size: 32;
    shadow-inset: 8;
}

.confirm-title {
    font-size: 16;
    color: 0xFFFFD700;
    auto-size: grow fit;
}

.confirm-desc {
    font-size: 13;
    auto-size: grow fit;
    padding: 0 0 8 0;
}

.confirm-actions {
    auto-size: grow fit;
    gap: 8;
}
